    "href": "/deep-dives/streaming-swaps-refunds",
    "type": "deep-dive",
    "title": "Streaming Swaps And Refunds",
    "description": "Streaming Swaps And Refunds THORChain swaps are not just a formula.",
    "confidence": "curated",
    "reviewedAt": "2026-07-13",
